using Contoso.Text;

namespace Contoso.Text.Tests;

[TestClass]
public class StringFormatterTests
{
    private readonly StringFormatter _formatter = new();

    // --- FormatPhoneNumber ---

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_StartsWithAreaCodeInParens()
    {
        string result = _formatter.FormatPhoneNumber("2125551234");

        StringAssert.StartsWith(result, "(212)");
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_EndsWithLastFourDigits()
    {
        string result = _formatter.FormatPhoneNumber("2125551234");

        StringAssert.EndsWith(result, "1234");
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_ReturnsFullFormat()
    {
        string result = _formatter.FormatPhoneNumber("8005551234");

        Assert.AreEqual("(800) 555-1234", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_NullInput_ThrowsArgumentNullException()
    {
        Assert.ThrowsException<ArgumentNullException>(() => _formatter.FormatPhoneNumber(null!));
    }

    [TestMethod]
    public void FormatPhoneNumber_WrongLength_ThrowsArgumentException()
    {
        Assert.ThrowsException<ArgumentException>(() => _formatter.FormatPhoneNumber("123"));
    }

    // --- BuildGreeting ---

    [TestMethod]
    public void BuildGreeting_WithDefaultTitle_StartsWithDearMr()
    {
        string result = _formatter.BuildGreeting("Smith");

        StringAssert.StartsWith(result, "Dear Mr.");
    }

    [TestMethod]
    public void BuildGreeting_WithDefaultTitle_EndsWithComma()
    {
        string result = _formatter.BuildGreeting("Smith");

        StringAssert.EndsWith(result, ",");
    }

    [TestMethod]
    public void BuildGreeting_WithCustomTitle_StartsWithDearAndTitle()
    {
        string result = _formatter.BuildGreeting("Johnson", "Dr.");

        StringAssert.StartsWith(result, "Dear Dr.");
    }

    [TestMethod]
    public void BuildGreeting_WithCustomTitle_ContainsName()
    {
        string result = _formatter.BuildGreeting("Johnson", "Dr.");

        StringAssert.Contains(result, "Johnson");
    }

    [TestMethod]
    public void BuildGreeting_WhitespaceName_ThrowsArgumentException()
    {
        Assert.ThrowsException<ArgumentException>(() => _formatter.BuildGreeting("   "));
    }

    // --- GenerateSlug ---

    [TestMethod]
    public void GenerateSlug_SimpleTitle_ReturnsLowercaseHyphenated()
    {
        string result = _formatter.GenerateSlug("Hello World");

        Assert.AreEqual("hello-world", result);
    }

    [TestMethod]
    public void GenerateSlug_TitleWithPrefix_StartsWithExpectedSlug()
    {
        string result = _formatter.GenerateSlug("Getting Started with C#");

        StringAssert.StartsWith(result, "getting-started");
    }

    [TestMethod]
    public void GenerateSlug_TitleWithSuffix_EndsWithLastWord()
    {
        string result = _formatter.GenerateSlug("Introduction to Testing");

        StringAssert.EndsWith(result, "testing");
    }

    [TestMethod]
    public void GenerateSlug_SpecialCharacters_DoesNotStartWithHyphen()
    {
        string result = _formatter.GenerateSlug("  --Hello World--  ");

        Assert.IsFalse(result.StartsWith('-'));
        Assert.IsFalse(result.EndsWith('-'));
    }

    [TestMethod]
    public void GenerateSlug_WhitespaceTitle_ThrowsArgumentException()
    {
        Assert.ThrowsException<ArgumentException>(() => _formatter.GenerateSlug("  "));
    }

    // --- FormatCurrency ---

    [TestMethod]
    public void FormatCurrency_DefaultSymbol_StartsWithDollarSign()
    {
        string result = _formatter.FormatCurrency(19.99m);

        StringAssert.StartsWith(result, "$");
    }

    [TestMethod]
    public void FormatCurrency_CustomSymbol_StartsWithSymbol()
    {
        string result = _formatter.FormatCurrency(9.99m, "€");

        StringAssert.StartsWith(result, "€");
    }

    [TestMethod]
    public void FormatCurrency_WholeNumber_EndsWithTwoDecimalPlaces()
    {
        string result = _formatter.FormatCurrency(100m);

        StringAssert.EndsWith(result, ".00");
    }

    [TestMethod]
    public void FormatCurrency_NegativeAmount_StartsWithSymbolAndMinus()
    {
        string result = _formatter.FormatCurrency(-5.50m);

        StringAssert.StartsWith(result, "$-");
    }

    [TestMethod]
    public void FormatCurrency_PreciseAmount_ReturnsExactValue()
    {
        string result = _formatter.FormatCurrency(1234.56m, "£");

        Assert.AreEqual("£1234.56", result);
    }
}

